CREATE FUNCTION "insert_account_activity"()
  RETURNS "pg_catalog"."trigger" AS $BODY$
            BEGIN
            INSERT INTO account_activity(account_id) VALUES (NEW.id);
            RETURN NEW;
            END$BODY$
  LANGUAGE plpgsql VOLATILE
  COST 100;
ALTER FUNCTION "insert_account_activity"() OWNER TO "postgres";
CREATE FUNCTION "insert_player_stats"()
  RETURNS "pg_catalog"."trigger" AS $BODY$
            BEGIN
            INSERT INTO player_stats(player_id) VALUES (NEW.id);
            RETURN NEW;
            END$BODY$
  LANGUAGE plpgsql VOLATILE
  COST 100;
ALTER FUNCTION "insert_player_stats"() OWNER TO "postgres";
